import "core-js/modules/es6.regexp.to-string";
import { isvalidUsername } from '@/utils/validate';
import { getApiUrl } from '@/utils/utils';
import AesUtil from "@/utils/aes.js";
import { getQrcodeStatus } from '@/api/user';
import LangSelect from '@/components/LangSelect';
import register from '@/views/system/user/register';
import alent from '@/views/protal/view/alent';
export default {
  name: 'login',
  components: {
    LangSelect: LangSelect,
    register: register
  },
  data: function data() {
    var _this = this;
    var validateUsername = function validateUsername(rule, value, callback) {
      if (!isvalidUsername(value)) {
        callback(new Error(_this.$t('login.errorAccount')));
      } else {
        callback();
      }
    };
    var validatePassword = function validatePassword(rule, value, callback) {
      if (value.length < 2) {
        callback(new Error(_this.$t('login.errorPassword')));
      } else {
        callback();
      }
    };
    return {
      isVisible: true,
      qrcode: {
        activeName: 'first',
        showAppdownload: false,
        imgUrl: '',
        uuid: '',
        resultStatus: '',
        msg: '请使用flash-uniapp 扫码登录'
      },
      loginForm: {
        username: '',
        password: ''
      },
      loginRules: {
        username: [{
          required: true,
          trigger: 'blur',
          validator: validateUsername
        }],
        password: [{
          required: true,
          trigger: 'blur',
          validator: validatePassword
        }]
      },
      loading: false,
      pwdType: 'password',
      redirect: '/index'
    };
  },
  mounted: function mounted() {
    this.init();
    this.getQrcode();
  },
  methods: {
    init: function init() {
      var redirect = this.$route.query.redirect;
      if (redirect) {
        this.redirect = redirect;
      }
    },
    //打开弹窗
    openModal: function openModal() {
      this.isVisible = true;
    },
    //关闭弹窗
    closeModal: function closeModal() {
      this.isVisible = false;
    },
    changeLoginType: function changeLoginType(tab) {
      if (this.qrcode.activeName === 'second') {
        this.getQrcode();
        //this.getQrcodeResult()
      }
    },
    uuid: function uuid() {
      function S4() {
        return ((1 + Math.random()) * 0x10000 | 0).toString(16).substring(1);
      }
      return S4() + S4() + '-' + S4() + '-' + S4() + '-' + S4() + '-' + S4() + S4() + S4();
    },
    showAppdownload: function showAppdownload() {
      this.qrcode.showAppdownload = true;
    },
    hideAppdownload: function hideAppdownload() {
      this.qrcode.showAppdownload = false;
    },
    getQrcode: function getQrcode() {
      this.qrcode.uuid = this.uuid();
      var url = getApiUrl() + '/account/qrcode/generate?uuid=' + this.qrcode.uuid;
      console.log('getQrcode', url);
      this.qrcode.imgUrl = url;
    },
    refreshQrcode: function refreshQrcode() {
      this.getQrcode();
      this.qrcode.resultStatus = '';
      //this.getQrcodeResult()
    },
    getQrcodeResult: function getQrcodeResult() {
      var _this2 = this;
      if (this.qrcode.activeName === 'second') {
        var me = this;
        this.sleep(1000).then(function () {
          getQrcodeStatus({
            uuid: me.qrcode.uuid
          }).then(function (res) {
            _this2.qrcode.resultStatus = res.data.status;
            if (res.data.status === 'invalid') {
              _this2.qrcode.showAppdownload = false;
              me.qrcode.msg = '二维码已过期';
            }
            if (res.data.status === 'success') {
              _this2.qrcode.showAppdownload = false;
              _this2.qrcode.msg = '扫描成功，自动登录中';
              _this2.loading = true;
              _this2.$store.dispatch('user/autoLogin', {
                token: res.data.token
              }).then(function () {
                _this2.loading = false;
                _this2.$router.push({
                  path: _this2.redirect
                });
              }).catch(function (err) {
                _this2.qrcode.msg = '登录失败';
                _this2.loading = false;
              });
            }
            if (me.qrcode.activeName === 'second' && res.data.status === 'undo') {
              //me.getQrcodeResult()
            }
          }).catch(function (err) {
            console.log('err', err);
          });
        });
      }
    },
    sleep: function sleep(time) {
      return new Promise(function (resolve) {
        return setTimeout(resolve, time);
      });
    },
    showPwd: function showPwd() {
      if (this.pwdType === 'password') {
        this.pwdType = '';
      } else {
        this.pwdType = 'password';
      }
    },
    handleLogin: function handleLogin() {
      var _this3 = this;
      var loginForm = this.loginForm;
      debugger;
      this.$refs.loginForm.validate(function (valid) {
        if (valid) {
          _this3.loading = true;
          var loginBody = {
            username: loginForm.username,
            password: AesUtil.encrypt(loginForm.password)
          };
          _this3.$store.dispatch('user/login', loginBody).then(function () {
            _this3.loading = false;
            _this3.$message({
              message: 'success',
              type: 'success'
            });
            _this3.$emit('send-data', true);
            _this3.$router.push({
              path: _this3.redirect
            });
          }).catch(function (err) {
            _this3.loading = false;
          });
        } else {
          return false;
        }
      });
    }
  }
};
